using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_d2d4e49ba8014741a572b83a05a03a06;

public class ServerAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _authState = Task.FromResult(
        new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(
            new[]
            {
                new Claim(ClaimTypes.Name, "bob@example.com"),
                new Claim(ClaimTypes.Email, "bob@example.com"),
                new Claim(ClaimTypes.Role, "User"),
                new Claim(ClaimTypes.Role, "Editor"),
            },
            authenticationType: "Hardcoded"))));

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

using System.Net.Http.Json;
using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_d2d4e49ba8014741a572b83a05a03a06.Client;

public class ClientAuthenticationStateProvider : AuthenticationStateProvider
{
    private readonly HttpClient _httpClient;

    public ClientAuthenticationStateProvider(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public override async Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        try
        {
            var userInfo = await _httpClient.GetFromJsonAsync<UserInfo>("api/auth/user");

            if (userInfo is { IsAuthenticated: true, Claims.Length: > 0 })
            {
                var claims = userInfo.Claims
                    .Select(c => new Claim(c.Type, c.Value))
                    .ToList();

                var identity = new ClaimsIdentity(claims, "ServerAuth");
                return new AuthenticationState(new ClaimsPrincipal(identity));
            }
        }
        catch
        {
            // Fall through to anonymous
        }

        return new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity()));
    }
}

public record UserInfo(bool IsAuthenticated, ClaimRecord[] Claims);
public record ClaimRecord(string Type, string Value);

@page "/profile"
@using Microsoft.AspNetCore.Components.Authorization
@rendermode InteractiveAuto
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

@if (_name is not null)
{
    <p><strong>Name:</strong> @_name</p>
    <h3>Roles</h3>
    <ul>
        @foreach (var role in _roles)
        {
            <li>@role</li>
        }
    </ul>
}
else
{
    <p>Loading...</p>
}

@code {
    private string? _name;
    private List<string> _roles = new();

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var user = authState.User;

        if (user.Identity?.IsAuthenticated == true)
        {
            _name = user.Identity.Name;
            _roles = user.FindAll(System.Security.Claims.ClaimTypes.Role)
                         .Select(c => c.Value)
                         .ToList();
        }
    }
}

