using sv_d2d4e49ba8014741a572b83a05a03a06.Client.Pages;
using sv_d2d4e49ba8014741a572b83a05a03a06.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<AuthenticationStateProvider, ServerAuthenticationStateProvider>();

var app = builder.Build();

app.UseAntiforgery();

// Endpoint to expose auth claims to the WebAssembly client
app.MapGet("api/auth/user", async (AuthenticationStateProvider authStateProvider) =>
{
    var authState = await authStateProvider.GetAuthenticationStateAsync();
    var user = authState.User;

    if (user.Identity?.IsAuthenticated != true)
        return Results.Ok(new UserInfo(false, Array.Empty<ClaimRecord>()));

    var claims = user.Claims
        .Select(c => new ClaimRecord(c.Type, c.Value))
        .ToArray();

    return Results.Ok(new UserInfo(true, claims));
});

app.MapStaticAssets();

using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using sv_d2d4e49ba8014741a572b83a05a03a06.Client;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped(sp =>
    new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<AuthenticationStateProvider, ClientAuthenticationStateProvider>();

await builder.Build().RunAsync();

